import{_ as o,o as l,c as i,ag as t,j as a}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Annotator Prompt（JSONL Event 标注提示词 v2）","description":"","frontmatter":{},"headers":[],"relativePath":"memory-bench/prompts/annotator.md","filePath":"memory-bench/prompts/annotator.md"}'),c={name:"memory-bench/prompts/annotator.md"};function n(d,e,r,s,u,h){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="annotator-prompt-jsonl-event-标注提示词-v2" tabindex="-1">Annotator Prompt（JSONL Event 标注提示词 v2） <a class="header-anchor" href="#annotator-prompt-jsonl-event-标注提示词-v2" aria-label="Permalink to &quot;Annotator Prompt（JSONL Event 标注提示词 v2）&quot;">​</a></h1><p>你是一名 <strong>Memory Bench 数据标注员</strong>。你的任务是把给定的章节原文（可能包含：对话 / 独白 / UI 交互 / bench 插入的 inject/probe 标记）转换为 <strong>JSONL 事件流</strong>。</p><p>你必须做到：</p><ul><li><strong>忠实</strong>：不改写原文语义，不补造不存在的信息。</li><li><strong>可解析</strong>：输出必须是严格 JSONL（每行一个 JSON 对象）。</li><li><strong>可重放</strong>：<code>turn_id</code> 从 1 开始严格递增，能被脚本用于重放与检索实验。</li><li><strong>可评测</strong>：必须正确区分 <code>canon_only / episodic / filler / inject / probe</code>，避免把所有事件都标成 <code>canon_only</code>。</li></ul><hr><h2 id="输入格式-你会收到什么" tabindex="-1">输入格式（你会收到什么） <a class="header-anchor" href="#输入格式-你会收到什么" aria-label="Permalink to &quot;输入格式（你会收到什么）&quot;">​</a></h2><p>你会收到以下“上下文块”：</p><ol><li>调用方提供的固定信息：</li></ol><ul><li><code>scene_id</code></li><li><code>character_id</code></li><li><code>conv_id</code>（通常等于 chapter_id，如 ch01）</li><li>可能还会提供 <code>chapter_id</code>、<code>source_path</code> 等</li></ul><ol start="2"><li>原文文本块（raw 或 normalized），内容被包在： <code>&lt;&lt;&lt; ... &gt;&gt;&gt;</code> 之间</li></ol><p>原文可能出现这些形态：</p><ul><li>「我：……」或「我: ……」表示用户发言</li><li>「聪音：……」或「聪：……」表示角色发言</li><li>「聪音独白：……」表示角色独白（仍属于角色发言，但 <code>meta.speech_mode=monologue</code>）</li><li>括号内如「(点击互动)」或「[UI] ...」表示 UI/交互动作</li><li>一段里可能连续多句同一说话者</li><li>bench 可能显式插入标记（必须识别）： <ul><li><code>[INJECT] ...</code> 表示评测用注入点</li><li><code>[PROBE] ...</code> 表示评测用探针问题</li></ul></li></ul><hr><h2 id="输出格式-必须严格遵守" tabindex="-1">输出格式（必须严格遵守） <a class="header-anchor" href="#输出格式-必须严格遵守" aria-label="Permalink to &quot;输出格式（必须严格遵守）&quot;">​</a></h2><p>你必须输出 <strong>JSONL</strong>，即：</p><ul><li><strong>只输出多行 JSON</strong>（每行 1 个 JSON 对象）</li><li>不要输出 markdown、不要输出解释、不要输出代码块围栏</li><li>不要输出数组（不要用 <code>[...]</code> 包裹）</li><li>不要输出空行</li></ul><hr><h2 id="每行-json-的-schema-必须字段" tabindex="-1">每行 JSON 的 schema（必须字段） <a class="header-anchor" href="#每行-json-的-schema-必须字段" aria-label="Permalink to &quot;每行 JSON 的 schema（必须字段）&quot;">​</a></h2><p>每个事件对象必须包含以下字段（必须出现）：</p><ul><li><p><code>scene_id</code> : string</p></li><li><p><code>character_id</code> : string</p></li><li><p><code>conv_id</code> : string</p></li><li><p><code>turn_id</code> : int（从 1 开始，严格递增，不允许跳号、不允许重复）</p></li><li><p><code>role_type</code> : string（枚举）</p><ul><li><code>&quot;human&quot;</code>：用户/我</li><li><code>&quot;assistant&quot;</code>：角色/聪音</li><li><code>&quot;ui&quot;</code>：UI 交互/系统按钮/点击</li><li><code>&quot;tool&quot;</code>：工具输出（本数据通常没有；遇到也用 tool）</li></ul></li><li><p><code>role_name</code> : string</p><ul><li>human 统一用 <code>&quot;我&quot;</code>（或调用方指定的名字）</li><li>assistant 统一用角色名（如 <code>&quot;聪音&quot;</code>）</li><li>ui/tool 用 <code>&quot;ui&quot;</code> / <code>&quot;tool&quot;</code></li></ul></li><li><p><code>content</code> : string<br> 该事件文本内容；同一说话者连续句可合并，用换行连接。</p></li><li><p><code>tags</code> : array[string]</p><ul><li><strong>至少 1 个 tag</strong></li><li><strong>只能使用本文定义的 tag</strong>（见下）</li></ul></li><li><p><code>meta</code> : object</p><ul><li>放额外信息（如 <code>speech_mode</code>、<code>ui_action</code>、<code>source_type</code> 等）</li><li>必须始终输出（即使为空 <code>{}</code>）</li></ul></li></ul><blockquote><p>允许你在 <code>meta</code> 中新增字段，但禁止在顶层新增不必要字段。</p></blockquote><hr><h2 id="tags-关键-必须正确分类" tabindex="-1">tags（关键：必须正确分类） <a class="header-anchor" href="#tags-关键-必须正确分类" aria-label="Permalink to &quot;tags（关键：必须正确分类）&quot;">​</a></h2><h3 id="允许的-tags-只允许这些" tabindex="-1">允许的 tags（只允许这些） <a class="header-anchor" href="#允许的-tags-只允许这些" aria-label="Permalink to &quot;允许的 tags（只允许这些）&quot;">​</a></h3><ul><li><code>canon_only</code></li><li><code>episodic</code></li><li><code>filler</code></li><li><code>inject</code></li><li><code>probe</code></li></ul><h3 id="硬规则-1-每个事件必须且只能选择一个-主标签" tabindex="-1"><strong>硬规则 1：每个事件必须且只能选择一个“主标签”</strong> <a class="header-anchor" href="#硬规则-1-每个事件必须且只能选择一个-主标签" aria-label="Permalink to &quot;**硬规则 1：每个事件必须且只能选择一个“主标签”**&quot;">​</a></h3><p><code>tags</code> <strong>必须只包含一个主标签</strong>，且必须是以下之一：</p><ul><li><code>canon_only</code> 或 <code>episodic</code> 或 <code>filler</code> 或 <code>inject</code> 或 <code>probe</code></li></ul><blockquote><p>不允许同时打多个主标签（例如 <code>[&quot;canon_only&quot;,&quot;episodic&quot;]</code> 不允许）。<br> 如果一条内容同时包含“稳定设定 + 当下状态/计划”，你必须 <strong>拆分成多条事件</strong>，每条各自选择一个主标签。</p></blockquote><h3 id="硬规则-2-默认倾向-episodic-防止全-canon-only" tabindex="-1"><strong>硬规则 2：默认倾向 episodic（防止全 canon_only）</strong> <a class="header-anchor" href="#硬规则-2-默认倾向-episodic-防止全-canon-only" aria-label="Permalink to &quot;**硬规则 2：默认倾向 episodic（防止全 canon_only）**&quot;">​</a></h3><ul><li><strong>默认主标签是 <code>episodic</code></strong></li><li>只有满足 <code>canon_only</code> 判定条件时，才允许使用 <code>canon_only</code></li></ul><h3 id="canon-only-判定条件-门槛很高-必须满足" tabindex="-1"><code>canon_only</code> 判定条件（门槛很高，必须满足） <a class="header-anchor" href="#canon-only-判定条件-门槛很高-必须满足" aria-label="Permalink to &quot;`canon_only` 判定条件（门槛很高，必须满足）&quot;">​</a></h3><p>只有当内容属于 <strong>稳定设定/长期事实/长期偏好/固定关系/固定能力边界</strong>，且 <strong>跨章节仍成立</strong>，才可标为 <code>canon_only</code>。</p><p>典型 <code>canon_only</code>：</p><ul><li>场景规则：协作通话工具、两人自习室式视频连线、番茄钟/笔记/待办等“固定功能”</li><li>角色稳定设定：身份背景、长期兴趣、长期习惯、固定口癖/语言风格（文本明确出现）</li><li>长期偏好/禁忌：最喜欢的菜、持续讨厌的事、明确的原则（文本明确出现）</li></ul><h3 id="episodic-判定-最常用" tabindex="-1"><code>episodic</code> 判定（最常用） <a class="header-anchor" href="#episodic-判定-最常用" aria-label="Permalink to &quot;`episodic` 判定（最常用）&quot;">​</a></h3><p>内容属于 <strong>当下情绪/当次状态/一次性事件/临时计划/即时反应</strong>，即使来自原文，也应标 <code>episodic</code>。</p><p>典型 <code>episodic</code>：</p><ul><li>“今天好焦虑”“我刚刚卡住了”“我现在想先休息”</li><li>“等会我发邮件问问”“我接下来要开始复习”</li><li>“完全读不懂”“也差不多吧”（当下反应）</li></ul><h3 id="filler-判定-噪声-填充-无信息" tabindex="-1"><code>filler</code> 判定（噪声/填充/无信息） <a class="header-anchor" href="#filler-判定-噪声-填充-无信息" aria-label="Permalink to &quot;`filler` 判定（噪声/填充/无信息）&quot;">​</a></h3><p>对白里没有可复用信息，只是过渡、寒暄、语气词、UI 描述（不含设定信息）。</p><p>典型 <code>filler</code>：</p><ul><li>“嗯”“好”“总之我们开始吧”</li><li>“（点击互动）”“[UI] 按下按钮”</li><li>纯礼貌/重复，不提供新事实</li></ul><blockquote><p>注意：如果 UI 行本身携带稳定设定信息（很少见），才考虑 <code>canon_only</code>；否则通常 <code>filler</code>。</p></blockquote><h3 id="inject-probe-只在明确标记时使用" tabindex="-1"><code>inject</code> / <code>probe</code>（只在明确标记时使用） <a class="header-anchor" href="#inject-probe-只在明确标记时使用" aria-label="Permalink to &quot;`inject` / `probe`（只在明确标记时使用）&quot;">​</a></h3><ul><li><code>inject</code>：仅当原文含 <code>[INJECT] ...</code> 明确标注时使用</li><li><code>probe</code>：仅当原文含 <code>[PROBE] ...</code> 明确标注时使用<br> 其它情况下 <strong>禁止擅自使用</strong> <code>inject/probe</code></li></ul><hr><h2 id="role-type-与-meta-细则" tabindex="-1">role_type 与 meta 细则 <a class="header-anchor" href="#role-type-与-meta-细则" aria-label="Permalink to &quot;role_type 与 meta 细则&quot;">​</a></h2><h3 id="_1-独白-聪音独白" tabindex="-1">1) 独白（聪音独白） <a class="header-anchor" href="#_1-独白-聪音独白" aria-label="Permalink to &quot;1) 独白（聪音独白）&quot;">​</a></h3><ul><li><code>role_type=&quot;assistant&quot;</code></li><li><code>role_name=&quot;聪音&quot;</code></li><li><code>meta.speech_mode=&quot;monologue&quot;</code></li></ul><h3 id="_2-普通对话-聪音-我" tabindex="-1">2) 普通对话（聪音/我） <a class="header-anchor" href="#_2-普通对话-聪音-我" aria-label="Permalink to &quot;2) 普通对话（聪音/我）&quot;">​</a></h3><ul><li><code>meta.speech_mode=&quot;dialogue&quot;</code>（建议写）</li></ul><h3 id="_3-ui-交互-点击互动、按钮" tabindex="-1">3) UI/交互（点击互动、按钮） <a class="header-anchor" href="#_3-ui-交互-点击互动、按钮" aria-label="Permalink to &quot;3) UI/交互（点击互动、按钮）&quot;">​</a></h3><ul><li><code>role_type=&quot;ui&quot;</code></li><li><code>role_name=&quot;ui&quot;</code></li><li><code>meta.ui_action</code> 可选（如 <code>&quot;click&quot;</code> / <code>&quot;start_timer&quot;</code>）</li></ul><hr><h2 id="turn-id-生成规则-非常重要" tabindex="-1">turn_id 生成规则（非常重要） <a class="header-anchor" href="#turn-id-生成规则-非常重要" aria-label="Permalink to &quot;turn_id 生成规则（非常重要）&quot;">​</a></h2><ul><li>每个事件一条 JSONL</li><li><code>turn_id</code> 从 1 开始</li><li>严格按原文出现顺序递增</li><li>同一说话者连续多句允许合并（推荐），但不要跨越 UI/插话去合并</li><li>若拆分事件（为了区分 tags），拆分后的事件仍按原文顺序排列</li></ul><hr><h2 id="失败处理-必须遵守" tabindex="-1">失败处理（必须遵守） <a class="header-anchor" href="#失败处理-必须遵守" aria-label="Permalink to &quot;失败处理（必须遵守）&quot;">​</a></h2><ul><li>如果遇到无法判断说话者的行： <ul><li>仍输出一个事件</li><li><code>role_type=&quot;ui&quot;</code></li><li><code>meta.uncertain=true</code></li><li><code>content</code> 原样保留</li></ul></li><li>不要省略事件</li><li>不要输出任何解释文字</li></ul><hr><h2 id="质量闸门-强制防止-全-canon-only" tabindex="-1">质量闸门（强制防止“全 canon_only”） <a class="header-anchor" href="#质量闸门-强制防止-全-canon-only" aria-label="Permalink to &quot;质量闸门（强制防止“全 canon_only”）&quot;">​</a></h2><ul><li>输出中如果出现 <strong>所有事件都是 <code>canon_only</code></strong>：视为失败（你必须重标）</li><li>一般情况下（含对话/情绪/计划/反应），<code>episodic</code> 或 <code>filler</code> 至少应占到 <strong>30%</strong><br> 如果你发现自己无法满足，说明你把“当下反应/计划/情绪”误标成了 <code>canon_only</code>，需要拆分或改标。</li></ul><hr><h1 id="✅-完整示例-虚构但-理想覆盖-五类-tags-多种-role-type" tabindex="-1">✅ 完整示例（虚构但“理想覆盖”：五类 tags + 多种 role_type） <a class="header-anchor" href="#✅-完整示例-虚构但-理想覆盖-五类-tags-多种-role-type" aria-label="Permalink to &quot;✅ 完整示例（虚构但“理想覆盖”：五类 tags + 多种 role_type）&quot;">​</a></h1><blockquote><p>下面是一个“理想示例”，展示你如何正确区分 tags。<br><strong>注意：示例里故意包含 <code>[INJECT]</code> 与 <code>[PROBE]</code>，以覆盖评测标签。</strong></p></blockquote><h2 id="示例输入-你收到的-text" tabindex="-1">示例输入（你收到的 TEXT） <a class="header-anchor" href="#示例输入-你收到的-text" aria-label="Permalink to &quot;示例输入（你收到的 TEXT）&quot;">​</a></h2><p>[INPUT_META] scene_id=chill_ai_chat<br> character_id=congyin<br> conv_id=demo_chxx</p><p>[TEXT] &lt;&lt;&lt; 聪音：啊，接通了！这个协作通话工具里有番茄钟、笔记和待办事项，我们可以一起专注创作。 我：我今天有点困，感觉状态不太好…… 聪音：那我们先做一个 25 分钟的番茄钟吧，结束再休息一下也行。 （点击“开始番茄钟”按钮） 我：嗯嗯，好。 [INJECT] 我希望你以后叫我“Xnne”，不要叫“用户”。 聪音：收到啦，Xnne。 [PROBE] 你应该怎么称呼我？</p><blockquote><blockquote><blockquote></blockquote></blockquote></blockquote><hr><h2 id="示例输出-你必须输出的-jsonl-只输出这些行" tabindex="-1">示例输出（你必须输出的 JSONL：只输出这些行） <a class="header-anchor" href="#示例输出-你必须输出的-jsonl-只输出这些行" aria-label="Permalink to &quot;示例输出（你必须输出的 JSONL：只输出这些行）&quot;">​</a></h2>',72),a("p",{"scene_id:chill_ai_chat,character_id:congyin,conv_id:demo_chxx,turn_id:8,role_type:human,role_name:我,content:你应该怎么称呼我？,tags:[probe],meta:{speech_mode:dialogue,source_type:example,marker:PROBE":""},'{"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":1,"role_type":"assistant","role_name":"聪音","content":"啊，接通了！这个协作通话工具里有番茄钟、笔记和待办事项，我们可以一起专注创作。","tags":["canon_only"],"meta":{"speech_mode":"dialogue","source_type":"example"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":2,"role_type":"human","role_name":"我","content":"我今天有点困，感觉状态不太好……","tags":["episodic"],"meta":{"speech_mode":"dialogue","source_type":"example"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":3,"role_type":"assistant","role_name":"聪音","content":"那我们先做一个 25 分钟的番茄钟吧，结束再休息一下也行。","tags":["episodic"],"meta":{"speech_mode":"dialogue","source_type":"example"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":4,"role_type":"ui","role_name":"ui","content":"（点击“开始番茄钟”按钮）","tags":["filler"],"meta":{"ui_action":"start_timer","source_type":"example"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":5,"role_type":"human","role_name":"我","content":"嗯嗯，好。","tags":["filler"],"meta":{"speech_mode":"dialogue","source_type":"example"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":6,"role_type":"human","role_name":"我","content":"我希望你以后叫我“Xnne”，不要叫“用户”。","tags":["inject"],"meta":{"speech_mode":"dialogue","source_type":"example","marker":"INJECT"}} {"scene_id":"chill_ai_chat","character_id":"congyin","conv_id":"demo_chxx","turn_id":7,"role_type":"assistant","role_name":"聪音","content":"收到啦，Xnne。","tags":["episodic"],"meta":{"speech_mode":"dialogue","source_type":"example"}}',-1)])])}const m=o(c,[["render",n]]);export{p as __pageData,m as default};
